USE P21;
SET NOCOUNT ON; SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
SELECT result_set='settings_columns', table_name=t.name, column_name=c.name
FROM sys.tables t JOIN sys.schemas s ON s.schema_id=t.schema_id JOIN sys.columns c ON c.object_id=t.object_id
WHERE s.name='dbo' AND (c.name LIKE '%alloc%' OR c.name LIKE '%reserve%' OR c.name LIKE '%backorder%' OR c.name LIKE '%commit%') AND (t.name LIKE '%system%' OR t.name LIKE '%setting%' OR t.name LIKE '%company%' OR t.name LIKE '%location%' OR t.name LIKE '%inv_loc%' OR t.name LIKE '%oe%')
ORDER BY t.name,c.name;
SELECT result_set='module_transfer_reserve_lines', object_name=OBJECT_SCHEMA_NAME(m.object_id)+'.'+OBJECT_NAME(m.object_id), snippet=SUBSTRING(m.definition, NULLIF(CHARINDEX('oe_transfer_reserve_flag',m.definition)-500,-500), 2000)
FROM sys.sql_modules m WHERE m.definition LIKE '%oe_transfer_reserve_flag%';
SELECT result_set='module_anticipated_lines', object_name=OBJECT_SCHEMA_NAME(m.object_id)+'.'+OBJECT_NAME(m.object_id), snippet=SUBSTRING(m.definition, NULLIF(CHARINDEX('anticipated_allocation',m.definition)-500,-500), 2000)
FROM sys.sql_modules m WHERE m.definition LIKE '%anticipated_allocation%' AND (m.definition LIKE '%oe_line%' OR m.definition LIKE '%transfer%');
